interface UserForm {
  uid: string;
  firstName: string;
  lastName: string;
  email: string;
  old: number;
}

@Component({
  templateUrl: './inu-input-text.view.html',
  styleUrls: ['./inu-input-text.view.scss'],
  imports: [
    InuCode,
    InuInputText,
    InuCode,
    InuTableFlex,
    InuTableFlexHeader,
    InuTableFlexRow,
    InuTableFlexCell,
    InuPanelTabs,
    InuPanelTab,
    FormField
  ]
})
export class InuInputTextView {

  data = signal<string>('');
  userModel = signal<UserForm>({
    uid: '',
    firstName: '',
    lastName: '',
    email: '',
    old : 0
  });

  userForm: FieldTree<UserForm>  = form(this.userModel, (path) => {
    required(path.email);
  });


  constructor() {
    toObservable(this.userModel)
      .pipe(
        debounceTime(200),
        distinctUntilChanged(),
        takeUntilDestroyed()
      )
      .subscribe(value => {
        this.onValueChanged(value)
      });
  }

  private onValueChanged(value: UserForm) {
    this.data.set(JSON.stringify(value, null, 4));
  }
}
